-- MedLink seed data (MySQL).
-- Populates the database with the mock data that previously lived hardcoded in
-- the mobile-medlink (Ionic/Angular) frontend, so the integrated app has real
-- data to read.
--
-- Run AFTER schema.sql, into the `medlink` database:
--   mysql -u medlink -p medlink < src/config/schema.sql
--   mysql -u medlink -p medlink < src/config/seed.sql
--
-- Notes / decisions:
--   * The frontend's browsable medication catalog has no dedicated table; the 20
--     catalog meds are seeded as `donations` with status 'aprovado' so they show
--     up in GET /api/donations?status=aprovado and GET /api/donations/:id.
--   * ALL seed users share the password "senha123" (bcrypt hash below). Log in
--     with e.g. ana.silva@email.com / senha123 or admin@medlink.com / senha123.
--   * Binary columns (identity_document, photo) are NOT NULL, so they are filled
--     with a 1x1 transparent PNG placeholder (image/png).
--   * This script is idempotent: it truncates the four tables and re-seeds with
--     fixed ids so foreign keys line up deterministically.

SET NAMES utf8mb4;

-- Shared bcrypt hash of "senha123" (cost 10) and a 1x1 transparent PNG placeholder.
SET @pw  = '$2b$10$4ZW3QR9ib/07D5kMlge.7O7sZRPYKoow8bwuVEwkOudmFmqFRGc3e';
SET @png = FROM_BASE64('iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNk+M8AAAMBAQDJ/pLvAAAAAElFTkSuQmCC');

-- Reset (children first via FK-checks off, then TRUNCATE to reset AUTO_INCREMENT).
SET FOREIGN_KEY_CHECKS = 0;
TRUNCATE TABLE requests;
TRUNCATE TABLE donations;
TRUNCATE TABLE users;
TRUNCATE TABLE partners;
SET FOREIGN_KEY_CHECKS = 1;

